import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import { HTMLAttributes } from 'react';
import { FileState, FileUploaderFile } from '../../FileUploader.types';
export interface FileUploaderListItem extends Pick<FileUploaderFile, 'id' | 'name' | 'state' | 'iconName'> {
    type?: FileUploaderFile['type'];
}
export interface FileUploaderListItemProps extends Omit<HTMLAttributes<HTMLDivElement>, 'id'> {
    id?: FileUploaderListItem['id'];
    name: FileUploaderListItem['name'];
    state?: FileUploaderListItem['state'];
    iconName?: FileUploaderListItem['iconName'];
    type?: FileUploaderListItem['type'];
    helperText?: string;
    percent?: number;
    size?: string;
    loaded?: string;
    actions?: FileUploaderListItemAction[] | React.ReactNode;
    /** Обработчик события удаления файла */
    onRemove?: (fileName: FileUploaderListItem) => void;
    /** Обработчик события повторной отправки файла */
    onRefresh?: (fileName: FileUploaderListItem) => void;
}
export interface FileUploaderListItemAction {
    tooltip?: string;
    icon: Icons;
    onClick: (fileName: FileUploaderListItem) => void;
    showStatuses?: FileState[];
}
